SQL:
SELECT MIN(ser_start) AS earliest_start
FROM callcenterlogs
WHERE `Date received` = '2017-03-22';

SELECT COUNT(*)
FROM course
WHERE diff = (SELECT MAX(diff) FROM course);

SELECT COUNT(DISTINCT device_model)
FROM phone_brand_device_model2
WHERE phone_brand = 'vivo';

WITH pembroke AS (
  SELECT `patient` FROM `patients` WHERE `birthplace` = 'Pembroke MA US'
),
grass AS (
  SELECT DISTINCT `PATIENT` FROM `allergies` WHERE `DESCRIPTION` = 'Allergy to grass pollen'
)
SELECT 100.0 * (SELECT COUNT(*) FROM pembroke p JOIN grass g ON p.patient = g.PATIENT)
       / (SELECT COUNT(*) FROM pembroke) AS percentage;

SELECT
  (SELECT COUNT(DISTINCT `Order ID`) FROM east_superstore  WHERE strftime('%Y', `Order Date`) = '2015') AS east_orders,
  (SELECT COUNT(DISTINCT `Order ID`) FROM west_superstore  WHERE strftime('%Y', `Order Date`) = '2015') AS west_orders;

SELECT 100.0 * SUM(race = 'B') / COUNT(*) AS pct_black_male_officers
FROM (
  SELECT DISTINCT `full_name`, `race`
  FROM `officers`
  WHERE `gender` = 'M'
);

SELECT so.OrderNumber, p.`Product Name`
FROM `Sales Orders` so
JOIN Products p ON p.ProductID = so._ProductID
WHERE CAST(REPLACE(so.`Unit Price`, ',', '') AS REAL) = (
    SELECT MIN(CAST(REPLACE(`Unit Price`, ',', '') AS REAL)) FROM `Sales Orders`
);

SELECT COUNT(DISTINCT COALESCE(`playerID`, `firstName` || ' ' || `lastName`)) AS num_joe_players
FROM `draft`
WHERE `firstName` = 'Joe' AND `draftYear` = 1970;

SELECT 100.0 * SUM(`oRebounds`) / SUM(`rebounds`) AS percentage_off_reb
FROM `players_teams`
WHERE `year` = 2000;

SELECT SUM(`stars` * `votes`) * 1.0 / SUM(`votes`) AS average_stars
FROM `Vote`
WHERE `episode_id` = (
        SELECT `episode_id` FROM `Episode`
        WHERE `title` = 'Wedding for Disaster'
);

SELECT `name`
FROM `disabled`
WHERE `name` NOT IN (SELECT `name` FROM `male`);

with sub1  as (SELECT DISTINCT city, state FROM `area_code` ac JOIN `zip_data` zd ON ac.`zip_code` = zd.`zip_code` WHERE ac.`area_code` = 787 AND zd.`type` = 'P.O. Box Only' ),
sub2 as (
SELECT DISTINCT `city`, state FROM `area_code` ac JOIN `zip_data` zd ON ac.`zip_code` = zd.`zip_code` WHERE ac.`area_code` = 787 AND zd.`type` = 'Post Office' 
)
SELECT (SELECT count(*) from sub1) - (SELECT count(*) from sub2) ;

SELECT COUNT(*)
FROM Menu
WHERE sponsor = 'PACIFIC MAIL STEAMSHIP COMPANY' AND page_count <= 2;

SELECT ABS(
         (SELECT `cost` FROM `shipping_method` WHERE `method_name` = 'Priority')
       - (SELECT `cost` FROM `shipping_method` WHERE `method_name` = 'Express')
) AS cost_difference;

SELECT COUNT(*)
FROM establishment
WHERE risk_level = (SELECT MAX(risk_level) FROM establishment);

SELECT `ContactName`
FROM `Suppliers`
WHERE `SupplierName` = 'Heli Süßwaren GmbH & Co. KG';

SELECT `CustomerName`, `Address`
FROM `Customers`
WHERE `City` = 'London';

SELECT AVG(`VacationHours`) AS avg_vacation_hours
FROM `Employee`
WHERE `Gender` = 'M';

SELECT SUM(`ActualCost`) - SUM(`PlannedCost`) AS difference
FROM `WorkOrderRouting`
WHERE `ProductID` = 818;

SELECT JULIANDAY(`EndDate`) - JULIANDAY(`StartDate`) AS days_to_finish
FROM `WorkOrder`
WHERE `WorkOrderID` = 425;

SELECT CAST(`W` AS REAL) / `G` AS winning_rate
FROM `Teams`
WHERE `name` = 'Buffalo Sabres' AND `year` = 2000;

SELECT c.`Name`
FROM `City` AS c
JOIN `Country` AS co ON c.`CountryCode` = co.`Code`
WHERE co.`LifeExpectancy` = (
        SELECT MAX(`LifeExpectancy`) FROM `Country`
);

SELECT `ranking_criteria_id`, `score`
FROM `university_ranking_year`
WHERE `university_id` = 68 AND `year` = 2015;

SELECT 100.0 * SUM(CASE WHEN `FTAG` = 2 THEN 1 ELSE 0 END) / COUNT(*) AS away_two_goal_percentage
FROM `matchs`
WHERE `season` = 2017;

SELECT COUNT(DISTINCT `voice-actor`)
FROM `voice-actors`
WHERE `movie` = 'Bambi';
